// import React, { useEffect, useRef, useState } from "react";

const DEFAULT_DATA = {
  name: "Akash Chavan",
  title: "Full Stack Developer",
  subtitle: "Fintech & Investment Platforms",
  tagline:
    "Building enterprise-grade systems for 90M+ investor accounts — where performance, security, and scale are non-negotiable.",
  contact: {
    email: "chavanak870@gmail.com",
    linkedin: "linkedin.com/in/akashchavan",
    github: "github.com/akashchavan",
  },
  stats: [
    { value: "90M+",  label: "Investor Accounts Served" },
    { value: "3.5+",  label: "Years Experience" },
    { value: "35+",   label: "RESTful APIs Built" },
    { value: "99.9%", label: "API Uptime SLA" },
  ],
};

const TECH_TAGS = [
  { label: "React",      color: "#61dafb" },
  { label: "Node.js",    color: "#68a063" },
  { label: "TypeScript", color: "#3178c6" },
  { label: "PostgreSQL", color: "#336791" },
  { label: "Redis",      color: "#d82c20" },
  { label: "AWS",        color: "#ff9900" },
  { label: "Docker",     color: "#0db7ed" },
  { label: "GraphQL",    color: "#e535ab" },
  { label: "Kubernetes", color: "#326ce5" },
  { label: "Kafka",      color: "#00e5ff" },
];

export default function Hero({ data = DEFAULT_DATA }) {
  const d = {
    ...DEFAULT_DATA,
    ...data,
    contact: { ...DEFAULT_DATA.contact, ...(data?.contact || {}) },
  };
  const { name, title, subtitle, tagline, contact, stats } = d;

  const [mounted, setMounted] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 50, y: 35 });
  const heroRef = useRef(null);

  useEffect(() => {
    const t = setTimeout(() => setMounted(true), 60);
    const handleMouse = (e) => {
      if (!heroRef.current) return;
      const rect = heroRef.current.getBoundingClientRect();
      setMousePos({
        x: ((e.clientX - rect.left) / rect.width) * 100,
        y: ((e.clientY - rect.top) / rect.height) * 100,
      });
    };
    window.addEventListener("mousemove", handleMouse);
    return () => { clearTimeout(t); window.removeEventListener("mousemove", handleMouse); };
  }, []);

  const parts = (name || "Akash Chavan").split(" ");
  const firstName = parts[0];
  const lastName  = parts.slice(1).join(" ");

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@300;400;500&display=swap');

        .hs-root *, .hs-root *::before, .hs-root *::after { box-sizing: border-box; margin: 0; padding: 0; }

        @keyframes hs-fadeUp   { from{opacity:0;transform:translateY(26px)} to{opacity:1;transform:translateY(0)} }
        @keyframes hs-slideR   { from{opacity:0;transform:translateX(-18px)} to{opacity:1;transform:translateX(0)} }
        @keyframes hs-fadeIn   { from{opacity:0} to{opacity:1} }
        @keyframes hs-pulse    { 0%,100%{box-shadow:0 0 0 0 rgba(0,229,255,.5)} 50%{box-shadow:0 0 0 6px rgba(0,229,255,0)} }
        @keyframes hs-grad     { 0%{background-position:0% 50%} 50%{background-position:100% 50%} 100%{background-position:0% 50%} }
        @keyframes hs-float    { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-14px) rotate(1deg)} }
        @keyframes hs-scrollW  { 0%{transform:translateY(0);opacity:1} 60%{transform:translateY(10px);opacity:0} 61%{transform:translateY(0);opacity:0} 100%{opacity:1} }

        .hs-root {
          position:relative; min-height:100svh; background:#050810;
          overflow:hidden; display:flex; flex-direction:column;
          justify-content:center; font-family:'DM Sans',sans-serif; color:#f0f4ff;
        }
        .hs-bg { position:absolute; inset:0; transition:background .5s ease; }
        .hs-noise {
          position:absolute; inset:0; opacity:.35; pointer-events:none;
          background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='.04'/%3E%3C/svg%3E");
          background-size:200px;
        }
        .hs-grid {
          position:absolute; inset:0;
          background-image:linear-gradient(rgba(0,229,255,.025) 1px,transparent 1px),linear-gradient(90deg,rgba(0,229,255,.025) 1px,transparent 1px);
          background-size:clamp(30px,5vw,55px) clamp(30px,5vw,55px);
          mask-image:radial-gradient(ellipse 80% 80% at 50% 50%,black 20%,transparent 80%);
        }
        .hs-orb { position:absolute; border-radius:50%; pointer-events:none; filter:blur(65px); }
        .hs-o1  { width:clamp(180px,35vw,480px); height:clamp(180px,35vw,480px); top:-10%; right:-8%; background:radial-gradient(circle,rgba(124,58,237,.16) 0%,transparent 70%); animation:hs-float 9s ease-in-out infinite; }
        .hs-o2  { width:clamp(140px,25vw,340px); height:clamp(140px,25vw,340px); bottom:5%; left:-5%; background:radial-gradient(circle,rgba(0,229,255,.11) 0%,transparent 70%); animation:hs-float 7s ease-in-out -3s infinite; }
        .hs-o3  { width:clamp(90px,14vw,200px); height:clamp(90px,14vw,200px); top:42%; right:22%; background:radial-gradient(circle,rgba(245,158,11,.07) 0%,transparent 70%); animation:hs-float 11s ease-in-out -6s infinite; }

        .hs-wrap { position:relative; z-index:10; width:100%; max-width:min(1160px,92vw); margin:0 auto; padding:clamp(80px,12vw,120px) 0 clamp(50px,6vw,70px); }

        .hs-badge { display:inline-flex; align-items:center; gap:8px; background:rgba(0,229,255,.06); border:1px solid rgba(0,229,255,.22); border-radius:99px; padding:6px 16px 6px 10px; margin-bottom:clamp(1.2rem,3vw,1.8rem); opacity:0; animation:hs-slideR .6s cubic-bezier(.22,1,.36,1) .1s forwards; }
        .hs-bdot { width:8px; height:8px; border-radius:50%; background:#00e5ff; flex-shrink:0; animation:hs-pulse 2s ease infinite; }
        .hs-btxt { font-size:clamp(.6rem,1.2vw,.72rem); color:#00e5ff; font-weight:700; font-family:'Syne',sans-serif; letter-spacing:.1em; text-transform:uppercase; white-space:nowrap; }

        .hs-name { font-family:'Syne',sans-serif; font-weight:800; line-height:.95; letter-spacing:-.04em; font-size:clamp(3rem,10vw,8.5rem); color:#f0f4ff; margin-bottom:clamp(.5rem,1.5vw,.9rem); opacity:0; animation:hs-fadeUp .75s cubic-bezier(.22,1,.36,1) .25s forwards; word-break:break-word; hyphens:auto; }
        .hs-grad { background:linear-gradient(135deg,#00e5ff 0%,#5b8def 40%,#7c3aed 100%); background-size:200% auto; -webkit-background-clip:text; -webkit-text-fill-color:transparent; background-clip:text; animation:hs-grad 4s ease infinite; display:inline-block; }

        .hs-role { font-family:'Syne',sans-serif; font-size:clamp(.85rem,2vw,1.2rem); font-weight:500; color:#8899aa; margin-bottom:clamp(.75rem,2vw,1.1rem); opacity:0; animation:hs-fadeUp .7s cubic-bezier(.22,1,.36,1) .4s forwards; display:flex; align-items:center; flex-wrap:wrap; gap:clamp(4px,.8vw,8px); }
        .hs-rsep { width:4px; height:4px; border-radius:50%; background:rgba(255,255,255,.15); flex-shrink:0; }
        .hs-rhl  { color:#f59e0b; font-weight:700; }

        .hs-tl { font-size:clamp(.88rem,1.6vw,1.05rem); color:rgba(136,153,170,.85); max-width:min(540px,90vw); line-height:1.8; margin-bottom:clamp(1.5rem,4vw,2.5rem); font-weight:300; opacity:0; animation:hs-fadeUp .7s cubic-bezier(.22,1,.36,1) .55s forwards; }

        .hs-btns { display:flex; gap:clamp(.6rem,1.5vw,.9rem); flex-wrap:wrap; opacity:0; animation:hs-fadeUp .7s cubic-bezier(.22,1,.36,1) .7s forwards; }

        .hs-bp { position:relative; display:inline-flex; align-items:center; gap:8px; padding:clamp(10px,2vw,13px) clamp(20px,3.5vw,28px); background:#00e5ff; color:#000; font-family:'Syne',sans-serif; font-weight:700; font-size:clamp(.78rem,1.4vw,.88rem); letter-spacing:.03em; border-radius:99px; text-decoration:none; transition:transform .25s,box-shadow .25s,background .25s; white-space:nowrap; overflow:hidden; }
        .hs-bp:hover { transform:translateY(-3px); box-shadow:0 12px 36px rgba(0,229,255,.4); background:#1af0ff; }
        .hs-bg2 { display:inline-flex; align-items:center; gap:8px; padding:clamp(10px,2vw,13px) clamp(20px,3.5vw,28px); background:transparent; color:#f0f4ff; font-family:'Syne',sans-serif; font-weight:600; font-size:clamp(.78rem,1.4vw,.88rem); border:1px solid rgba(255,255,255,.07); border-radius:99px; text-decoration:none; transition:all .25s; white-space:nowrap; }
        .hs-bg2:hover { border-color:rgba(124,58,237,.6); color:#c4aaff; background:rgba(124,58,237,.08); transform:translateY(-2px); }
        .hs-bgk { display:inline-flex; align-items:center; gap:8px; padding:clamp(10px,2vw,13px) clamp(20px,3.5vw,28px); background:rgba(255,255,255,.04); color:#8899aa; font-family:'Syne',sans-serif; font-weight:600; font-size:clamp(.78rem,1.4vw,.88rem); border:1px solid rgba(255,255,255,.07); border-radius:99px; text-decoration:none; transition:all .25s; white-space:nowrap; }
        .hs-bgk:hover { background:rgba(255,255,255,.08); color:#f0f4ff; border-color:rgba(255,255,255,.15); transform:translateY(-2px); }

        .hs-div { width:100%; height:1px; background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.07) 20%,rgba(0,229,255,.15) 50%,rgba(255,255,255,.07) 80%,transparent 100%); margin:clamp(1.8rem,4vw,2.8rem) 0; opacity:0; animation:hs-fadeIn .6s ease 1s forwards; }

        .hs-stats { display:grid; grid-template-columns:repeat(4,1fr); gap:1px; background:rgba(255,255,255,.07); border:1px solid rgba(255,255,255,.07); border-radius:14px; overflow:hidden; opacity:0; animation:hs-fadeUp .7s cubic-bezier(.22,1,.36,1) 1.1s forwards; }
        .hs-sc   { background:rgba(13,17,23,.92); padding:clamp(.9rem,2.5vw,1.4rem) clamp(.5rem,1.5vw,1rem); text-align:center; transition:background .2s; }
        .hs-sc:hover { background:rgba(255,255,255,.03); }
        .hs-sv   { font-family:'Syne',sans-serif; font-weight:800; font-size:clamp(1.4rem,3.5vw,2.2rem); background:linear-gradient(135deg,#00e5ff 0%,#5b8def 100%); -webkit-background-clip:text; -webkit-text-fill-color:transparent; background-clip:text; line-height:1.1; letter-spacing:-.02em; }
        .hs-sl   { font-size:clamp(.6rem,1vw,.7rem); color:#8899aa; margin-top:5px; font-weight:500; line-height:1.3; letter-spacing:.03em; }

        .hs-techs { display:flex; flex-wrap:wrap; gap:clamp(5px,1vw,8px); margin-top:clamp(1.2rem,3vw,1.8rem); opacity:0; animation:hs-fadeUp .6s ease 1.3s forwards; }
        .hs-tt    { display:inline-flex; align-items:center; gap:5px; padding:4px 12px; background:rgba(255,255,255,.03); border:1px solid rgba(255,255,255,.07); border-radius:99px; font-size:clamp(.6rem,1vw,.7rem); color:#8899aa; font-family:'Syne',sans-serif; font-weight:500; letter-spacing:.04em; transition:all .2s; white-space:nowrap; cursor:default; }
        .hs-tt:hover { border-color:rgba(0,229,255,.25); color:#00e5ff; background:rgba(0,229,255,.04); }
        .hs-td    { width:5px; height:5px; border-radius:50%; flex-shrink:0; }

        .hs-scroll  { position:absolute; bottom:clamp(16px,3vw,28px); left:50%; transform:translateX(-50%); display:flex; flex-direction:column; align-items:center; gap:6px; z-index:10; opacity:0; animation:hs-fadeIn 1s ease 1.8s forwards; }
        .hs-scroll-m { width:22px; height:36px; border:2px solid rgba(255,255,255,.15); border-radius:11px; display:flex; justify-content:center; padding-top:6px; }
        .hs-scroll-w { width:3px; height:7px; background:rgba(255,255,255,.3); border-radius:99px; animation:hs-scrollW 1.8s ease infinite; }
        .hs-scroll-l { font-size:.58rem; color:rgba(255,255,255,.2); font-family:'Syne',sans-serif; letter-spacing:.12em; text-transform:uppercase; }

        @media(min-width:2560px){ .hs-wrap{max-width:1600px} .hs-name{font-size:clamp(9rem,7vw,12rem)} .hs-sv{font-size:3rem} }
        @media(min-width:1920px) and (max-width:2559px){ .hs-wrap{max-width:1400px} .hs-name{font-size:clamp(8rem,7.5vw,10rem)} }
        @media(max-width:1279px){ .hs-name{font-size:clamp(3.5rem,8.5vw,7.5rem)} }
        @media(max-width:1023px){ .hs-name{font-size:clamp(3rem,9vw,6rem)} .hs-wrap{max-width:95vw} }
        @media(max-width:767px){ .hs-name{font-size:clamp(2.8rem,11vw,5rem)} .hs-stats{grid-template-columns:repeat(2,1fr)} }
        @media(max-width:599px){ .hs-name{font-size:clamp(2.5rem,13vw,4rem)} .hs-bp,.hs-bg2,.hs-bgk{font-size:.82rem;padding:11px 20px} }
        @media(max-width:479px){
          .hs-name{font-size:clamp(2.2rem,14vw,3.5rem)}
          .hs-wrap{max-width:100%;padding-left:5vw;padding-right:5vw;padding-top:75px}
          .hs-btns{flex-direction:column;align-items:stretch}
          .hs-bp,.hs-bg2,.hs-bgk{justify-content:center;width:100%;font-size:.88rem;padding:13px 22px}
          .hs-stats{grid-template-columns:repeat(2,1fr)}
          .hs-scroll{display:none}
        }
        @media(max-width:359px){ .hs-name{font-size:2rem} .hs-wrap{padding-left:4vw;padding-right:4vw} }
        @media(max-height:500px) and (orientation:landscape){ .hs-root{min-height:auto} .hs-wrap{padding-top:60px;padding-bottom:30px} .hs-name{font-size:clamp(2rem,7vh,3.5rem)} .hs-stats{grid-template-columns:repeat(4,1fr)} .hs-scroll{display:none} }
        @media(prefers-reduced-motion:reduce){ *,*::before,*::after{animation-duration:.01ms!important;transition-duration:.01ms!important} }
      `}</style>

      <section className="hs-root" ref={heroRef} id="about">
        <div
          className="hs-bg"
          style={{
            background: `
              radial-gradient(ellipse 80% 60% at ${mousePos.x * 0.3 + 55}% ${mousePos.y * 0.3 + 20}%, rgba(124,58,237,.14) 0%, transparent 60%),
              radial-gradient(ellipse 55% 50% at ${20 - mousePos.x * 0.05}% ${70 + mousePos.y * 0.05}%, rgba(0,229,255,.09) 0%, transparent 55%),
              radial-gradient(ellipse 35% 35% at 88% 85%, rgba(245,158,11,.06) 0%, transparent 50%),
              #050810
            `
          }}
        />
        <div className="hs-noise" />
        <div className="hs-grid" />
        <div className="hs-orb hs-o1" />
        <div className="hs-orb hs-o2" />
        <div className="hs-orb hs-o3" />

        <div className="hs-wrap">
          <div className="hs-badge">
            <span className="hs-bdot" />
            <span className="hs-btxt">Open to Opportunities</span>
          </div>

          <h1 className="hs-name">
            {firstName} <span className="hs-grad">{lastName}</span>
          </h1>

          <p className="hs-role">
            <span>{title}</span>
            <span className="hs-rsep" />
            <span className="hs-rhl">{subtitle}</span>
          </p>

          <p className="hs-tl">{tagline}</p>

          <div className="hs-btns">
            <a href={`mailto:${contact.email}`} className="hs-bp">
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <rect x="2" y="4" width="20" height="16" rx="2"/>
                <path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/>
              </svg>
              Get in Touch
            </a>
            <a href={`https://${contact.linkedin}`} target="_blank" rel="noreferrer" className="hs-bg2">
              <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor">
                <path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-2-2 2 2 0 0 0-2 2v7h-4v-7a6 6 0 0 1 6-6z"/>
                <rect x="2" y="9" width="4" height="12"/>
                <circle cx="4" cy="4" r="2"/>
              </svg>
              LinkedIn
            </a>
            <a href={`https://${contact.github}`} target="_blank" rel="noreferrer" className="hs-bgk">
              <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor">
                <path d="M9 19c-5 1.5-5-2.5-7-3m14 6v-3.87a3.37 3.37 0 0 0-.94-2.61c3.14-.35 6.44-1.54 6.44-7A5.44 5.44 0 0 0 20 4.77 5.07 5.07 0 0 0 19.91 1S18.73.65 16 2.48a13.38 13.38 0 0 0-7 0C6.27.65 5.09 1 5.09 1A5.07 5.07 0 0 0 5 4.77a5.44 5.44 0 0 0-1.5 3.78c0 5.42 3.3 6.61 6.44 7A3.37 3.37 0 0 0 9 18.13V22"/>
              </svg>
              GitHub
            </a>
          </div>

          <div className="hs-div" />

          <div className="hs-stats">
            {stats.map((s, i) => (
              <div key={i} className="hs-sc">
                <div className="hs-sv">{s.value}</div>
                <div className="hs-sl">{s.label}</div>
              </div>
            ))}
          </div>

          <div className="hs-techs">
            {TECH_TAGS.map((t, i) => (
              <span key={i} className="hs-tt">
                <span className="hs-td" style={{ background: t.color }} />
                {t.label}
              </span>
            ))}
          </div>
        </div>

        <div className="hs-scroll">
          <div className="hs-scroll-m"><div className="hs-scroll-w" /></div>
          <span className="hs-scroll-l">Scroll</span>
        </div>
      </section>
    </>
  );
}
